import React, { useState, useMemo, useEffect } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, 
  ComposedChart, Line, Cell
} from 'recharts';
import { GoogleGenAI } from "@google/genai";
import { TARGET_GOALS, MONTHS, SELLERS, YEARS, HISTORICAL_TOP_CLIENTS, HISTORICAL_YEARS } from './constants';
import { YearlyActualData, ChartDataPoint } from './types';

const formatBRL = (value: number): string => {
  try {
    return String(new Intl.NumberFormat('pt-BR', { 
      style: 'currency', 
      currency: 'BRL', 
      maximumFractionDigits: 0 
    }).format(Number(value) || 0));
  } catch (e) {
    return String(`R$ ${Number(value).toLocaleString('pt-BR')}`);
  }
};

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'goals' | 'clients' | 'growth'>('goals');
  const [selectedYear, setSelectedYear] = useState<string>('2026');

  // Persistence Layer
  const [actualData, setActualData] = useState<YearlyActualData>(() => {
    const initial: YearlyActualData = {};
    YEARS.forEach(yr => {
      initial[String(yr)] = {};
      MONTHS.forEach(m => { 
        initial[String(yr)][String(m)] = { syllas: 0, v1: 0, v2: 0, v3: 0 }; 
      });
    });
    try {
      const saved = localStorage.getItem('skg_bi_v11_actuals');
      if (saved) return { ...initial, ...JSON.parse(saved) };
    } catch (e) { console.warn("Cache error:", e); }
    return initial;
  });

  const [clientProjections, setClientProjections] = useState<Record<string, Record<number, number>>>(() => {
    const initial: Record<string, Record<number, number>> = {};
    HISTORICAL_TOP_CLIENTS.forEach(c => {
      initial[String(c.id)] = {};
      [2026, 2027, 2028, 2029, 2030].forEach(y => initial[String(c.id)][Number(y)] = 0);
    });
    try {
      const saved = localStorage.getItem('skg_bi_v11_projections');
      if (saved) return { ...initial, ...JSON.parse(saved) };
    } catch (e) { console.warn("Projections cache error:", e); }
    return initial;
  });

  useEffect(() => {
    localStorage.setItem('skg_bi_v11_actuals', JSON.stringify(actualData));
    localStorage.setItem('skg_bi_v11_projections', JSON.stringify(clientProjections));
  }, [actualData, clientProjections]);

  // BI Calculations - Monthly & Quarterly
  const biMetrics = useMemo(() => {
    const currentYearActuals = actualData[selectedYear] || {};
    let totalRealizado = 0;
    let totalMeta = 0;

    const monthlyData = TARGET_GOALS.map(goal => {
      const actual = currentYearActuals[goal.month] || { syllas: 0, v1: 0, v2: 0, v3: 0 };
      const real = (Number(actual.syllas) || 0) + (Number(actual.v1) || 0) + (Number(actual.v2) || 0) + (Number(actual.v3) || 0);
      totalRealizado += real;
      totalMeta += goal.total;
      return { 
        month: goal.month, 
        meta: goal.total, 
        realizado: real,
        gap: goal.total - real
      };
    });

    const quarterlyData = [
      { name: 'Q1', months: ['Jan', 'Fev', 'Mar'] },
      { name: 'Q2', months: ['Abr', 'Mai', 'Jun'] },
      { name: 'Q3', months: ['Jul', 'Ago', 'Set'] },
      { name: 'Q4', months: ['Out', 'Nov', 'Dez'] }
    ].map(q => {
      const qMeta = TARGET_GOALS.filter(g => q.months.includes(g.month)).reduce((acc, g) => acc + g.total, 0);
      const qReal = q.months.reduce((acc, m) => {
        const actual = currentYearActuals[m] || { syllas: 0, v1: 0, v2: 0, v3: 0 };
        return acc + (Number(actual.syllas) || 0) + (Number(actual.v1) || 0) + (Number(actual.v2) || 0) + (Number(actual.v3) || 0);
      }, 0);
      return { 
        name: q.name, 
        meta: qMeta, 
        realizado: qReal,
        percentage: qMeta > 0 ? (qReal / qMeta) * 100 : 0
      };
    });

    return { monthlyData, quarterlyData, totalRealizado, totalMeta, overallPercentage: (totalRealizado / totalMeta) * 100 };
  }, [actualData, selectedYear]);

  // AI Strategy States
  const [isConsulting, setIsConsulting] = useState(false);
  const [dailyReport, setDailyReport] = useState<string | null>(() => localStorage.getItem('skg_bi_v11_insight'));

  const fetchAIAnalysis = async () => {
    const apiKey = process.env.API_KEY;
    if (!apiKey) return alert("API Key não detectada.");
    setIsConsulting(true);
    try {
      const ai = new GoogleGenAI({ apiKey });
      const prompt = `Analise os dados da SK-G Automação: Meta Anual R$ 2.180.000, Realizado ${formatBRL(biMetrics.totalRealizado)} (${biMetrics.overallPercentage.toFixed(1)}%). Dê 3 dicas de Growth para bater a meta.`;
      const res = await ai.models.generateContent({ model: 'gemini-3-flash-preview', contents: prompt, config: { tools: [{googleSearch: {}}] } });
      const text = String(res.text);
      setDailyReport(text);
      localStorage.setItem('skg_bi_v11_insight', text);
    } catch (e) { console.error(e); } finally { setIsConsulting(false); }
  };

  const handleInputChange = (month: string, seller: string, value: string) => {
    const num = parseFloat(value.replace(/[R$\s.]/g, '').replace(',', '.')) || 0;
    setActualData(prev => ({
      ...prev,
      [selectedYear]: {
        ...(prev[selectedYear] || {}),
        [month]: { ...(prev[selectedYear]?.[month] || { syllas: 0, v1: 0, v2: 0, v3: 0 }), [seller]: num }
      }
    }));
  };

  return (
    <div className="min-h-screen flex flex-col bg-[#0b0e14] text-gray-100 pb-24 font-sans custom-scrollbar">
      {/* HEADER */}
