            </section>

            {/* DATA INPUT SECTION (SINGLE SOURCE OF TRUTH) */}
            <section className="bg-[#12161f] rounded-3xl border border-gray-800 shadow-2xl overflow-hidden">
              <div className="p-6 bg-gray-950/50 border-b border-gray-800 flex justify-between items-center">
