                    {TARGET_GOALS.map((goal) => {
                      const actual = (actualData[selectedYear] || {})[goal.month] || { syllas: 0, v1: 0, v2: 0, v3: 0 };
                      const totalReal = Object.values(actual).reduce((a, b) => a + Number(b), 0);
