export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, 
  ComposedChart, Line, Area, Cell
} from 'recharts';
import { GoogleGenAI } from "@google/genai";
import { TARGET_GOALS, MONTHS, SELLERS, YEARS, HISTORICAL_TOP_CLIENTS, HISTORICAL_YEARS } from './constants';
import { YearlyActualData, SellerActual } from './types';

const formatBRL = (value: number): string => {
  try {
    return String(new Intl.NumberFormat('pt-BR', { 
      style: 'currency', 
      currency: 'BRL', 
      maximumFractionDigits: 0 
    }).format(Number(value) || 0));
  } catch (e) {
    return String(`R$ ${Number(value).toLocaleString('pt-BR')}`);
  }
};

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'goals' | 'clients' | 'growth'>('goals');
  const [selectedYear, setSelectedYear] = useState<string>('2026');
  const [saveFeedback, setSaveFeedback] = useState<boolean>(false);

  // Persistence Layer - Initial Load from LocalStorage
  const [actualData, setActualData] = useState<YearlyActualData>(() => {
    const initial: YearlyActualData = {};
    YEARS.forEach(yr => {
      initial[String(yr)] = {};
      MONTHS.forEach(m => { 
        initial[String(yr)][String(m)] = { syllas: 0, v1: 0, v2: 0, v3: 0 }; 
      });
    });
    try {
      const saved = localStorage.getItem('skg_bi_data_v12');
      if (saved) return { ...initial, ...JSON.parse(saved) };
    } catch (e) { console.warn("Cache error:", e); }
    return initial;
  });

  const [clientProjections, setClientProjections] = useState<Record<string, Record<number, number>>>(() => {
    const initial: Record<string, Record<number, number>> = {};
    HISTORICAL_TOP_CLIENTS.forEach(c => {
      initial[String(c.id)] = {};
      [2026, 2027, 2028, 2029, 2030].forEach(y => initial[String(c.id)][Number(y)] = 0);
    });
    try {
      const saved = localStorage.getItem('skg_bi_v12_projections');
      if (saved) return { ...initial, ...JSON.parse(saved) };
    } catch (e) { console.warn("Projections cache error:", e); }
    return initial;
  });

  // Manual Save Function
  const handleSaveSales = () => {
    localStorage.setItem('skg_bi_data_v12', JSON.stringify(actualData));
    localStorage.setItem('skg_bi_v12_projections', JSON.stringify(clientProjections));
    setSaveFeedback(true);
    setTimeout(() => setSaveFeedback(false), 3000);
  };

  // BI Calculations - Monthly, Quarterly & Progressive Sums
  const biMetrics = useMemo(() => {
    const currentYearActuals = actualData[selectedYear] || {};
    let runningTotalRealizado = 0;
    let runningTotalMeta = 0;
    let totalMetaAnual = 2180000;

    const monthlyData = TARGET_GOALS.map(goal => {
      const actual = (currentYearActuals[goal.month] || { syllas: 0, v1: 0, v2: 0, v3: 0 }) as SellerActual;
      const realMes = (Number(actual.syllas) || 0) + (Number(actual.v1) || 0) + (Number(actual.v2) || 0) + (Number(actual.v3) || 0);

      runningTotalRealizado += realMes;
      runningTotalMeta += goal.total;

      return { 
        month: goal.month, 
        meta: goal.total, 
        realizado: realMes,
        acumuladoReal: runningTotalRealizado,
        acumuladoMeta: runningTotalMeta,
        gap: goal.total - realMes
      };
    });

    const quarterlyData = [
      { name: 'Q1', months: ['Jan', 'Fev', 'Mar'] },
      { name: 'Q2', months: ['Abr', 'Mai', 'Jun'] },
      { name: 'Q3', months: ['Jul', 'Ago', 'Set'] },
      { name: 'Q4', months: ['Out', 'Nov', 'Dez'] }
    ].map(q => {
      const qMeta = TARGET_GOALS.filter(g => q.months.includes(g.month)).reduce((acc, g) => acc + g.total, 0);
      const qReal = q.months.reduce((acc, m) => {
        const actual = (currentYearActuals[m] || { syllas: 0, v1: 0, v2: 0, v3: 0 }) as SellerActual;
        return acc + (Number(actual.syllas) || 0) + (Number(actual.v1) || 0) + (Number(actual.v2) || 0) + (Number(actual.v3) || 0);
      }, 0);
      return { 
        name: q.name, 
        meta: qMeta, 
        realizado: qReal,
        percentage: qMeta > 0 ? (qReal / qMeta) * 100 : 0
      };
    });

    return { 
      monthlyData, 
      quarterlyData, 
      totalRealizado: runningTotalRealizado, 
      totalMeta: totalMetaAnual, 
      overallPercentage: (runningTotalRealizado / totalMetaAnual) * 100 
    };
  }, [actualData, selectedYear]);

  // AI Strategy States & Cache logic
  const [isConsulting, setIsConsulting] = useState(false);
  const [dailyReport, setDailyReport] = useState<string | null>(() => localStorage.getItem('skg_bi_v12_insight'));

  const fetchAIAnalysis = async () => {
    const apiKey = process.env.API_KEY;
    if (!apiKey) return alert("API Key não detectada.");

    // Cache logic: Check if data has changed compared to last analysis (simplified)
    const currentDataKey = `${selectedYear}-${biMetrics.totalRealizado}`;
    if (localStorage.getItem('skg_bi_v12_last_key') === currentDataKey && dailyReport) {
      alert("A análise já está atualizada para os dados salvos.");
      return;
    }

    setIsConsulting(true);
    try {
      const ai = new GoogleGenAI({ apiKey });
      const topClients = HISTORICAL_TOP_CLIENTS.slice(0, 3).map(c => c.name).join(', ');

      const prompt = `
        Aja como Growth Advisor da V4 Company. 
        Analise o cenário da SK-G Automação Industrial:
        - Meta Anual: ${formatBRL(biMetrics.totalMeta)}
        - Realizado Acumulado: ${formatBRL(biMetrics.totalRealizado)}
        - Atingimento: ${biMetrics.overallPercentage.toFixed(1)}%
        - Clientes Foco T20: ${topClients}

        Se o atingimento estiver abaixo do esperado para o período atual, sugira estratégias de recuperação agressivas. 
        Utilize o histórico industrial para insights sobre o setor de automação.
      `;

      const res = await ai.models.generateContent({ 
        model: 'gemini-3-flash-preview', 
        contents: prompt, 
        config: { tools: [{googleSearch: {}}] } 
      });

      const text = String(res.text);
      setDailyReport(text);
      localStorage.setItem('skg_bi_v12_insight', text);
      localStorage.setItem('skg_bi_v12_last_key', currentDataKey);
    } catch (e) { 
      console.error(e); 
    } finally { 
      setIsConsulting(false); 
    }
  };

  const handleInputChange = (month: string, seller: string, value: string) => {
    const num = parseFloat(value.replace(/[R$\s.]/g, '').replace(',', '.')) || 0;
    setActualData(prev => ({
      ...prev,
      [selectedYear]: {
        ...(prev[selectedYear] || {}),
        [month]: { ...(prev[selectedYear]?.[month] || { syllas: 0, v1: 0, v2: 0, v3: 0 }), [seller]: num }
      }
    }));
  };

  return (
    <div className="min-h-screen flex flex-col bg-[#0b0e14] text-gray-100 pb-24 font-sans custom-scrollbar">
      {/* HEADER */}
      <header className="bg-[#cc1d1d] shadow-2xl p-4 flex flex-col md:flex-row items-center justify-between sticky top-0 z-50 gap-4">
        <div className="flex items-center gap-4">
          <img src="https://imgur.com/Ky5zDy2.png" alt="SK-G" className="h-10 bg-white p-1 rounded-md" />
          <h1 className="text-xl font-black uppercase italic tracking-tighter">SK-G Intelligence BI</h1>
        </div>
        <nav className="flex bg-red-900/40 p-1 rounded-xl border border-red-500/30">
          {['goals', 'clients', 'growth'].map((tab) => (
            <button key={tab} onClick={() => setActiveTab(tab as any)} className={`px-5 py-2 rounded-lg text-[10px] font-black uppercase transition-all ${activeTab === tab ? 'bg-white text-red-700 shadow-md' : 'text-white/70 hover:bg-red-700/40'}`}>
              {tab === 'goals' ? 'Dashboard Geral' : tab === 'clients' ? 'Top 20 Clientes' : 'Estratégia V4'}
            </button>
          ))}
        </nav>
        <div className="flex items-center gap-2">
          {YEARS.slice(0, 3).map(yr => (
            <button key={yr} onClick={() => setSelectedYear(yr)} className={`px-3 py-1.5 rounded-lg text-xs font-black transition-all ${selectedYear === yr ? 'bg-white text-red-700 shadow-md' : 'text-white/50 hover:text-white'}`}>{yr}</button>
          ))}
        </div>
      </header>

      <main className="flex-1 p-4 md:p-8 space-y-8 max-w-[1800px] mx-auto w-full">
        {activeTab === 'goals' && (
          <div className="animate-in fade-in duration-500 space-y-8">
            {/* KPI TOP SECTION */}
            <section className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
              <div className="bg-[#12161f] p-6 rounded-3xl border border-gray-800 shadow-xl relative overflow-hidden group">
                <div className="absolute top-0 left-0 w-1 h-full bg-emerald-500"></div>
                <p className="text-[10px] font-black text-gray-500 uppercase tracking-widest mb-1 italic">Revenue Acumulado</p>
                <p className="text-3xl font-black text-emerald-400">{formatBRL(biMetrics.totalRealizado)}</p>
                <p className="text-[9px] text-gray-600 mt-2 font-bold">TOTAL REALIZADO NO ANO</p>
              </div>
              <div className="bg-[#12161f] p-6 rounded-3xl border border-gray-800 shadow-xl relative overflow-hidden">
                <div className="absolute top-0 left-0 w-1 h-full bg-amber-500"></div>
                <p className="text-[10px] font-black text-gray-500 uppercase tracking-widest mb-1 italic">Atingimento Anual</p>
                <p className="text-3xl font-black text-amber-400">{String(biMetrics.overallPercentage.toFixed(1))}%</p>
                <div className="h-2 w-full bg-gray-900 rounded-full mt-3 overflow-hidden">
                  <div className="h-full bg-amber-500" style={{width: `${Math.min(100, biMetrics.overallPercentage)}%`}}></div>
                </div>
              </div>
              <div className="bg-[#12161f] p-6 rounded-3xl border border-gray-800 shadow-xl relative overflow-hidden">
                <div className="absolute top-0 left-0 w-1 h-full bg-blue-500"></div>
                <p className="text-[10px] font-black text-gray-500 uppercase tracking-widest mb-1 italic">Status Trimestral</p>
                <p className="text-3xl font-black text-blue-400">{biMetrics.quarterlyData.filter(q => q.realizado > 0).length || 1} / 4</p>
                <p className="text-[9px] text-gray-600 mt-2 font-bold uppercase tracking-widest">Trimestres Ativos</p>
              </div>
              <div className="bg-[#12161f] p-6 rounded-3xl border border-gray-800 shadow-xl border-t-4 border-t-red-600">
                <p className="text-[10px] font-black text-gray-500 uppercase tracking-widest mb-1 italic">Gap p/ Meta</p>
                <p className="text-3xl font-black text-red-500">{formatBRL(Math.max(0, biMetrics.totalMeta - biMetrics.totalRealizado))}</p>
                <p className="text-[9px] text-gray-600 mt-2 font-bold uppercase tracking-widest">Faltante para Meta 2.18M</p>
              </div>
            </section>

            {/* CHARTS SECTION */}
            <section className="grid grid-cols-1 lg:grid-cols-2 gap-8">
              <div className="bg-[#12161f] p-8 rounded-3xl border border-gray-800 shadow-xl">
                <h3 className="text-lg font-black uppercase italic mb-8 tracking-widest">Crescimento Progressivo (Acumulado)</h3>
                <div className="h-[350px]">
                  <ResponsiveContainer width="100%" height="100%">
                    <ComposedChart data={biMetrics.monthlyData}>
                      <CartesianGrid stroke="#1f2937" vertical={false} strokeDasharray="3 3" />
                      <XAxis dataKey="month" stroke="#4b5563" fontSize={11} tickLine={false} axisLine={false} />
                      <YAxis stroke="#4b5563" fontSize={10} tickFormatter={v => `R$${v/1000}k`} tickLine={false} axisLine={false} />
                      <Tooltip contentStyle={{backgroundColor: '#030712', border: 'none', borderRadius: '12px', boxShadow: '0 10px 20px rgba(0,0,0,0.5)'}} />
                      <Legend iconType="circle" wrapperStyle={{paddingTop: '20px'}} />
                      <Area type="monotone" dataKey="acumuladoReal" name="Acumulado Realizado" fill="#10b981" fillOpacity={0.1} stroke="#10b981" strokeWidth={3} />
                      <Line type="monotone" dataKey="acumuladoMeta" name="Meta Acumulada" stroke="#1e3a8a" strokeDasharray="5 5" dot={false} strokeWidth={2} />
                    </ComposedChart>
                  </ResponsiveContainer>
                </div>
              </div>

              <div className="bg-[#12161f] p-8 rounded-3xl border border-gray-800 shadow-xl overflow-hidden relative">
                <h3 className="text-lg font-black uppercase italic mb-8 tracking-widest">Performance por Trimestre (BI)</h3>
                <div className="h-[350px]">
                  <ResponsiveContainer width="100%" height="100%">
                    <BarChart data={biMetrics.quarterlyData}>
                      <CartesianGrid stroke="#1f2937" vertical={false} />
                      <XAxis dataKey="name" stroke="#4b5563" fontSize={12} fontStyle="italic" />
                      <YAxis stroke="#4b5563" fontSize={10} tickFormatter={v => `R$${v/1000}k`} />
                      <Tooltip cursor={{fill: 'rgba(255,255,255,0.05)'}} contentStyle={{backgroundColor: '#030712', border: 'none', borderRadius: '12px'}} />
                      <Bar dataKey="realizado" name="Realizado Trimestral" radius={[6, 6, 0, 0]} barSize={50}>
                        {biMetrics.quarterlyData.map((entry, index) => (
                          <Cell key={`cell-${index}`} fill={entry.percentage >= 100 ? '#10b981' : '#a855f7'} />
                        ))}
                      </Bar>
                      <Bar dataKey="meta" name="Meta Trimestral" fill="#1e3a8a" radius={[6, 6, 0, 0]} barSize={10} />
                    </BarChart>
                  </ResponsiveContainer>
                </div>
                {biMetrics.quarterlyData.some(q => q.percentage >= 100) && (
                  <div className="absolute top-4 right-4 bg-emerald-600 text-[10px] font-black px-4 py-1 rounded-full animate-bounce shadow-lg">META BATIDA!</div>
                )}
              </div>
            </section>

            {/* DATA INPUT SECTION (SINGLE SOURCE OF TRUTH) */}
            <section className="bg-[#12161f] rounded-3xl border border-gray-800 shadow-2xl overflow-hidden">
              <div className="p-6 bg-gray-950/50 border-b border-gray-800 flex flex-col sm:flex-row justify-between items-center gap-4">
                <div className="flex items-center gap-4">
                  <h3 className="text-lg font-black uppercase italic tracking-widest">Input Estratégico de Faturamento</h3>
                  <span className="text-[10px] font-black text-red-500 bg-red-950/30 px-3 py-1 rounded-full border border-red-500/20">FONTE ÚNICA</span>
                </div>
                <button 
                  onClick={handleSaveSales} 
                  className={`px-8 py-2 rounded-xl font-black text-xs uppercase tracking-widest transition-all shadow-lg active:scale-95 flex items-center gap-2 ${saveFeedback ? 'bg-emerald-600' : 'bg-[#008f39] hover:bg-emerald-500'}`}
                >
                  {saveFeedback ? '✓ DADOS SINCRONIZADOS' : '💾 SALVAR LANÇAMENTOS'}
                </button>
              </div>
              <div className="overflow-x-auto">
                <table className="w-full text-left text-sm">
                  <thead className="bg-[#0b0e14] text-gray-500 text-[10px] uppercase font-black">
                    <tr>
                      <th className="px-6 py-5 sticky left-0 bg-[#0b0e14] z-10 border-r border-gray-800">Período</th>
                      {SELLERS.map(s => <th key={s.id} className="px-4 py-5 text-center">{s.label}</th>)}
                      <th className="px-6 py-5 text-center bg-gray-900/40">Realizado Mes</th>
                      <th className="px-6 py-5 text-center">Meta Mes</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-gray-800/40">
                    {biMetrics.monthlyData.map((row) => {
                      const actual = ((actualData[selectedYear] || {})[row.month] || { syllas: 0, v1: 0, v2: 0, v3: 0 }) as SellerActual;
                      const isOffTrack = row.realizado < row.meta && row.realizado > 0;
                      return (
                        <tr key={row.month} className="hover:bg-white/[0.01] transition-colors">
                          <td className="px-6 py-4 font-black text-gray-400 sticky left-0 bg-[#12161f] border-r border-gray-800">{row.month}</td>
                          {SELLERS.map((s) => (
                            <td key={s.id} className="px-2 py-2">
                              <input 
                                type="text" 
                                className="bg-gray-950 border border-gray-800 rounded-lg px-3 py-2 w-full text-center font-bold text-white focus:ring-1 focus:ring-emerald-500 outline-none transition-all placeholder:opacity-20" 
                                placeholder="0" 
                                value={(actual as any)[s.id] || ''}
                                onChange={(e) => handleInputChange(row.month, s.id, e.target.value)}
                              />
