                         </td>
                         <td className="px-4 py-3 text-center font-bold text-gray-400">{formatBRL(client.lastYear)}</td>
                         <td className="px-2 py-2 bg-red-900/5">
                           <input type="text" className="bg-gray-950/40 border border-gray-800/50 rounded-lg px-2 py-1.5 w-full text-center font-black text-red-200 outline-none" value={clientProjections[client.id]?.[2026] || ''} onChange={e => {
                             const val = parseFloat(e.target.value.replace(/[R$\s.]/g, '').replace(',', '.')) || 0;
                             setClientProjections(p => ({ ...p, [client.id]: { ...p[client.id], 2026: val } }));
                           }} />
                         </td>
                       </tr>
                     ))}
