      } 
    }));
  };

  const handleOpChange = (month: string, field: string, value: string) => {
    const num = parseFloat(value.replace(/[R$\s.]/g, '').replace(',', '.')) || 0;
    setOpData(prev => ({ 
      ...prev, 
      [selectedYear]: { 
        ...(prev[selectedYear] || {}), 
        [month]: { ...(prev[selectedYear]?.[month] || { zm: 0, terceiro: 0, correios: 0, mercadoria: 0 }), [field]: num } 
      } 
