export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, 
  ComposedChart, Line, Area, Cell, LineChart
} from 'recharts';
import { TARGET_GOALS, MONTHS, SELLERS, YEARS, HISTORICAL_TOP_CLIENTS, HISTORICAL_YEARS, INDIVIDUAL_METAS } from './constants';
import { YearlyActualData, SellerActual, YearlyOperationalData, MonthlyOperational } from './types';

// Prevenção Definitiva de React Error #31 - Retorna sempre String
const formatBRL = (value: number): string => {
  try {
    return String(new Intl.NumberFormat('pt-BR', { 
      style: 'currency', 
      currency: 'BRL', 
      maximumFractionDigits: 0 
    }).format(Number(value) || 0));
  } catch (e) {
    return String(`R$ ${Number(value).toLocaleString('pt-BR')}`);
  }
};

interface SKGDatabase {
  revenue: YearlyActualData;
  operational: YearlyOperationalData;
  projections: Record<string, Record<number, number>>;
  clientActivation: Record<string, Record<string, Record<string, boolean>>>; // Year -> Month -> ClientID -> Active
}

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'goals' | 'performance' | 'clients' | 'efficiency'>('goals');
  const [selectedYear, setSelectedYear] = useState<string>('2026');
  const [selectedMonth, setSelectedMonth] = useState<string>('Jan');
  const [saveFeedback, setSaveFeedback] = useState<boolean>(false);

  // Database Engine - Persistência Centralizada SK-G
  const [db, setDb] = useState<SKGDatabase>(() => {
    const initialRevenue: YearlyActualData = {};
    const initialOp: YearlyOperationalData = {};
    const initialProj: Record<string, Record<number, number>> = {};
    const initialActivation: Record<string, Record<string, Record<string, boolean>>> = {};

    YEARS.forEach(yr => {
      initialRevenue[String(yr)] = {};
      initialOp[String(yr)] = {};
      initialActivation[String(yr)] = {};
      MONTHS.forEach(m => { 
        initialRevenue[String(yr)][String(m)] = { syllas: 0, v1: 0, v2: 0, v3: 0 }; 
        initialOp[String(yr)][String(m)] = { zm: 0, terceiro: 0, correios: 0, mercadoria: 0 };
        initialActivation[String(yr)][String(m)] = {};
      });
    });

    HISTORICAL_TOP_CLIENTS.forEach(c => {
      initialProj[String(c.id)] = { 2026: 0, 2027: 0, 2028: 0 };
    });

    try {
      const saved = localStorage.getItem('SKG_DATABASE_FINAL');
      if (saved) {
        const parsed = JSON.parse(saved);
        return {
          revenue: { ...initialRevenue, ...parsed.revenue },
          operational: { ...initialOp, ...parsed.operational },
          projections: { ...initialProj, ...parsed.projections },
          clientActivation: { ...initialActivation, ...parsed.clientActivation }
        };
      }
    } catch (e) { console.warn("Hydration failed:", e); }
    return { revenue: initialRevenue, operational: initialOp, projections: initialProj, clientActivation: initialActivation };
  });

  const handleGlobalSave = () => {
    localStorage.setItem('SKG_DATABASE_FINAL', JSON.stringify(db));
    setSaveFeedback(true);
    setTimeout(() => setSaveFeedback(false), 2000);
  };

  // BI Metrics - Consolidação de Faturamento e Custos
  const biMetrics = useMemo(() => {
    const currentYearRevenue = db.revenue[selectedYear] || {};
    const currentYearOp = db.operational[selectedYear] || {};
    let totalRealizado = 0;
    let totalLogistica = 0;
    let totalMercadoria = 0;
    const metaAnualFixa = 2180000;

    const monthlyData = MONTHS.map(m => {
      const actual = (currentYearRevenue[m] || { syllas: 0, v1: 0, v2: 0, v3: 0 }) as SellerActual;
      const op = (currentYearOp[m] || { zm: 0, terceiro: 0, correios: 0, mercadoria: 0 }) as MonthlyOperational;

      const realMes = (Number(actual.syllas) || 0) + (Number(actual.v1) || 0) + (Number(actual.v2) || 0) + (Number(actual.v3) || 0);
      const logMes = (Number(op.zm) || 0) + (Number(op.terceiro) || 0) + (Number(op.correios) || 0);
      const mercMes = (Number(op.mercadoria) || 0);

      totalRealizado += realMes;
      totalLogistica += logMes;
      totalMercadoria += mercMes;

      const metaMesTotal = TARGET_GOALS.find(g => g.month === m)?.total || 0;
      const percLog = realMes > 0 ? (logMes / realMes) * 100 : 0;
      const percMerc = realMes > 0 ? (mercMes / realMes) * 100 : 0;

      return { 
        month: m, 
        meta: metaMesTotal, 
        realizado: realMes,
        logistica: logMes,
        mercadoria: mercMes,
        margem: realMes - logMes - mercMes,
        percLog,
        percMerc,
        syllas: actual.syllas,
        v1: actual.v1,
        v2: actual.v2,
        v3: actual.v3
      };
    });

    return { 
      monthlyData, 
      totalRealizado, 
      atingimento: (totalRealizado / metaAnualFixa) * 100,
      totalLogistica,
      totalMercadoria,
      margemBrutaAnual: totalRealizado - totalLogistica - totalMercadoria,
      avgLogPerc: totalRealizado > 0 ? (totalLogistica / totalRealizado) * 100 : 0
    };
  }, [db, selectedYear]);

  // Performance por Vendedor (Realizado vs Metas Fixas)
  const sellerPerformance = useMemo(() => {
    return SELLERS.map(s => {
      let realizadoVendedor = 0;
      let metaVendedor = 0;
      MONTHS.forEach(m => {
        const rev = db.revenue[selectedYear]?.[m] || { syllas: 0, v1: 0, v2: 0, v3: 0 };
        realizadoVendedor += (rev as any)[s.id] || 0;
        metaVendedor += INDIVIDUAL_METAS[s.id]?.[m] || 0;
      });
      return { id: s.id, label: s.label, realizado: realizadoVendedor, meta: metaVendedor, atingimento: metaVendedor > 0 ? (realizadoVendedor / metaVendedor) * 100 : 0 };
    });
  }, [db, selectedYear]);

  // Análise T20 e Custo de Oportunidade (Ociosidade Estratégica)
  const t20Analysis = useMemo(() => {
    let totalCustoOportunidadeMes = 0;

    const analysis = HISTORICAL_TOP_CLIENTS.map(client => {
      const lastYear = client.history[2025] || 0;
      const prevYear = client.history[2024] || 0;
      const mediaMensalHistorica = (lastYear + prevYear) / 24;

      const isActiveInMonth = db.clientActivation[selectedYear]?.[selectedMonth]?.[client.id] || false;
      const opportunityCost = !isActiveInMonth ? mediaMensalHistorica : 0;

      if (!isActiveInMonth) {
        totalCustoOportunidadeMes += mediaMensalHistorica;
      }

      const status: 'STAR' | 'CHURN' | 'STABLE' | 'DECREASE' = lastYear === 0 ? 'CHURN' : (lastYear > mediaMensalHistorica * 12 * 1.15 ? 'STAR' : 'STABLE');

      return { ...client, lastYear, status, mediaMensalHistorica, isActiveInMonth, opportunityCost };
    }).sort((a, b) => b.lastYear - a.lastYear);

    const t20Total2025 = analysis.reduce((sum, c) => sum + c.lastYear, 0);
    let cumulative = 0;
    const paretoData = analysis.map(c => {
      cumulative += c.lastYear;
      return { name: c.name.split(' ')[0], value: c.lastYear, cumulative: t20Total2025 > 0 ? (cumulative / t20Total2025) * 100 : 0 };
    });

    return { analysis, paretoData, totalCustoOportunidadeMes };
  }, [db, selectedYear, selectedMonth]);

  // Handlers de Input
  const handleRevenueInput = (month: string, seller: string, value: string) => {
    const num = parseFloat(value.replace(/[R$\s.]/g, '').replace(',', '.')) || 0;
    setDb(prev => ({
      ...prev,
      revenue: {
        ...prev.revenue,
        [selectedYear]: {
          ...prev.revenue[selectedYear],
          [month]: { ...prev.revenue[selectedYear][month], [seller]: num }
        }
      }
    }));
  };

  const handleOpInput = (month: string, field: string, value: string) => {
    const num = parseFloat(value.replace(/[R$\s.]/g, '').replace(',', '.')) || 0;
    setDb(prev => ({
      ...prev,
      operational: {
        ...prev.operational,
        [selectedYear]: {
          ...prev.operational[selectedYear],
          [month]: { ...prev.operational[selectedYear][month], [field]: num }
        }
      }
    }));
  };

  const toggleClientActivation = (clientId: string) => {
    setDb(prev => {
      const currentYear = prev.clientActivation[selectedYear] || {};
      const currentMonth = currentYear[selectedMonth] || {};
      const newValue = !currentMonth[clientId];
      return {
        ...prev,
        clientActivation: {
          ...prev.clientActivation,
          [selectedYear]: {
            ...currentYear,
            [selectedMonth]: { ...currentMonth, [clientId]: newValue }
          }
        }
      };
    });
  };

  return (
    <div className="min-h-screen flex flex-col bg-[#0b0e14] text-gray-100 pb-24 font-sans custom-scrollbar">
      {/* HEADER BI SK-G CORPORATIVO */}
      <header className="bg-[#cc1d1d] shadow-2xl p-4 flex flex-col md:flex-row items-center justify-between sticky top-0 z-50 gap-4 border-b border-red-800">
        <div className="flex items-center gap-4">
          <img src="https://imgur.com/Ky5zDy2.png" alt="SK-G" className="h-10 bg-white p-1 rounded-md" />
          <h1 className="text-xl font-black uppercase italic tracking-tighter">SK-G Intelligence BI</h1>
        </div>
        <nav className="flex bg-red-900/40 p-1 rounded-xl border border-red-500/30 overflow-x-auto">
          {['goals', 'performance', 'clients', 'efficiency'].map(t => (
            <button key={t} onClick={() => setActiveTab(t as any)} className={`px-5 py-2 rounded-lg text-[10px] font-black uppercase transition-all whitespace-nowrap ${activeTab === t ? 'bg-white text-red-700 shadow-md' : 'text-white/70 hover:bg-red-700/40'}`}>
              {t === 'goals' ? 'Faturamento' : t === 'performance' ? 'Performance Time' : t === 'clients' ? 'T20 / Ociosidade' : 'Custos e Margem'}
            </button>
          ))}
        </nav>
        <div className="flex items-center gap-4">
          <select value={selectedMonth} onChange={(e) => setSelectedMonth(e.target.value)} className="bg-red-900/40 border border-red-500/30 rounded-lg text-xs font-black px-3 py-1.5 outline-none">
            {MONTHS.map(m => <option key={m} value={m}>{String(m)}</option>)}
          </select>
          <div className="flex items-center gap-2">
            {YEARS.slice(0, 3).map(yr => (
              <button key={yr} onClick={() => setSelectedYear(yr)} className={`px-3 py-1.5 rounded-lg text-xs font-black transition-all ${selectedYear === yr ? 'bg-white text-red-700 shadow-md' : 'text-white/50 hover:text-white'}`}>{yr}</button>
            ))}
          </div>
        </div>
      </header>

      <main className="flex-1 p-4 md:p-8 space-y-8 max-w-[1800px] mx-auto w-full">
        {/* KPI CARDS - 4 COLUNAS WIDE */}
        <section className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
          <div className="bg-[#12161f] p-6 rounded-3xl border border-gray-800 shadow-xl border-l-4 border-l-emerald-500">
            <p className="text-[10px] font-black text-gray-500 uppercase tracking-widest mb-1 italic">Receita Bruta {String(selectedYear)}</p>
            <p className="text-3xl font-black text-emerald-400">{formatBRL(biMetrics.totalRealizado)}</p>
            <p className="text-[9px] text-gray-600 mt-2 font-bold uppercase">Volume Total do Time</p>
          </div>
          <div className="bg-[#12161f] p-6 rounded-3xl border border-gray-800 shadow-xl border-l-4 border-l-amber-500">
            <p className="text-[10px] font-black text-gray-500 uppercase tracking-widest mb-1 italic">Atingimento da Meta</p>
            <p className="text-3xl font-black text-amber-400">{String(biMetrics.atingimento.toFixed(1))}%</p>
            <div className="h-1.5 w-full bg-gray-900 rounded-full mt-3 overflow-hidden">
              <div className="h-full bg-amber-500" style={{width: `${Math.min(100, biMetrics.atingimento)}%`}}></div>
            </div>
          </div>
          <div className="bg-[#12161f] p-6 rounded-3xl border border-gray-800 shadow-xl border-l-4 border-l-red-500">
            <p className="text-[10px] font-black text-gray-500 uppercase tracking-widest mb-1 italic">Logística Total</p>
            <p className="text-3xl font-black text-red-400">{formatBRL(biMetrics.totalLogistica)}</p>
            <p className="text-[9px] text-gray-600 mt-2 font-bold uppercase">Representa {String(biMetrics.avgLogPerc.toFixed(1))}% do Fat.</p>
          </div>
          <div className="bg-[#12161f] p-6 rounded-3xl border border-gray-800 shadow-xl border-t-4 border-t-purple-600">
            <p className="text-[10px] font-black text-gray-500 uppercase tracking-widest mb-1 italic">Ociosidade (Oportunidade)</p>
            <p className="text-3xl font-black text-purple-400">{formatBRL(t20Analysis.totalCustoOportunidadeMes)}</p>
            <p className="text-[9px] text-gray-600 mt-2 font-bold uppercase">Potencial Recuperável no Mês</p>
          </div>
        </section>

        {activeTab === 'goals' && (
          <div className="animate-in fade-in duration-500 space-y-8">
            <section className="grid grid-cols-1 lg:grid-cols-2 gap-8">
              <div className="bg-[#12161f] p-8 rounded-3xl border border-gray-800 shadow-xl">
                <h3 className="text-lg font-black uppercase italic mb-8 tracking-widest">Faturamento vs Meta Geral</h3>
                <div className="h-[350px]">
                  <ResponsiveContainer width="100%" height="100%">
                    <BarChart data={biMetrics.monthlyData}>
                      <CartesianGrid stroke="#1f2937" vertical={false} strokeDasharray="3 3" />
                      <XAxis dataKey="month" stroke="#4b5563" fontSize={11} />
                      <YAxis stroke="#4b5563" fontSize={10} tickFormatter={v => `R$${v/1000}k`} />
