                            );
                          })}
                       </tbody>
                    </table>
                 </div>
              </div>
            </section>
          </div>
        )}
      </main>

      {/* FOOTER FINANCEIRO GLOBAL */}
      <footer className="fixed bottom-0 left-0 right-0 bg-[#008f39] p-4 z-50 border-t border-emerald-400/20 shadow-[0_-10px_40px_rgba(0,0,0,0.6)] backdrop-blur-md">
