            <section className="bg-[#12161f] p-8 rounded-3xl border border-gray-800 shadow-xl overflow-x-auto">
               <h3 className="text-lg font-black uppercase italic mb-8 tracking-widest text-red-500">Input de Custos Operacionais 2026 (Logística e Matéria-Prima)</h3>
               <table className="w-full text-left text-sm">
                  <thead className="bg-[#0b0e14] text-gray-500 text-[10px] uppercase font-black">
                    <tr>
                      <th className="px-6 py-5 border-r border-gray-800">Mês</th>
                      <th className="px-4 py-5 text-center">ZM Express</th>
                      <th className="px-4 py-5 text-center">Terc. Express</th>
                      <th className="px-4 py-5 text-center text-amber-400">Correios</th>
                      <th className="px-4 py-5 text-center bg-gray-900/40">Matéria-Prima</th>
                      <th className="px-6 py-5 text-center font-black">Peso Log %</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-gray-800/40">
                    {biMetrics.monthlyData.map(row => {
                      const op = (db.operational['2026'][row.month] || { zm: 0, terceiro: 0, correios: 0, mercadoria: 0 }) as MonthlyOperational;
                      return (
                        <tr key={row.month}>
                          <td className="px-6 py-4 font-black text-gray-400 border-r border-gray-800">{String(row.month)}</td>
                          <td className="px-2 py-2"><input type="text" className="bg-gray-950 border border-gray-800 rounded px-3 py-2 w-full text-center font-bold" value={op.zm || ''} onChange={e => handleOpInput(row.month, 'zm', e.target.value)} /></td>
                          <td className="px-2 py-2"><input type="text" className="bg-gray-950 border border-gray-800 rounded px-3 py-2 w-full text-center font-bold" value={op.terceiro || ''} onChange={e => handleOpInput(row.month, 'terceiro', e.target.value)} /></td>
                          <td className="px-2 py-2"><input type="text" className="bg-gray-950 border border-amber-500/20 rounded px-3 py-2 w-full text-center font-black text-amber-400" value={op.correios || ''} onChange={e => handleOpInput(row.month, 'correios', e.target.value)} /></td>
                          <td className="px-2 py-2 bg-gray-900/10"><input type="text" className="bg-gray-950 border border-gray-800 rounded px-3 py-2 w-full text-center font-bold opacity-70" value={op.mercadoria || ''} onChange={e => handleOpInput(row.month, 'mercadoria', e.target.value)} /></td>
                          <td className={`px-6 py-4 text-center font-black ${row.percLog > 9 ? 'text-red-500 animate-pulse' : 'text-emerald-400'}`}>{String(row.percLog.toFixed(1))}%</td>
                        </tr>
                      );
