import React, { useState, useMemo } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, 
  ComposedChart, Line, Area, Cell, AreaChart
} from 'recharts';
import { TARGET_GOALS, MONTHS, SELLERS, YEARS, HISTORICAL_TOP_CLIENTS, INDIVIDUAL_METAS } from './constants';
import { YearlyActualData, SellerActual, YearlyOperationalData, MonthlyOperational } from './types';

// Proteção Erro #31 - Garante saída String e Formatação Monetária BR
const formatBRL = (value: number): string => {
  try {
    return String(new Intl.NumberFormat('pt-BR', { 
      style: 'currency', 
      currency: 'BRL', 
      maximumFractionDigits: 0 
    }).format(Number(value) || 0));
  } catch (e) {
    return String(`R$ ${Number(value).toLocaleString('pt-BR')}`);
  }
};

interface SKGDatabase {
  revenue: YearlyActualData;
  operational: YearlyOperationalData;
  t20Projections: Record<string, Record<number, number>>; // ClientID -> Year -> Value
}

// Coordenadas fictícias para o Mapa SVG (Foco Brasil/Mercosul)
const CLIENT_LOCATIONS: Record<string, { x: number, y: number, region: string }> = {
  c1: { x: 320, y: 380, region: 'Paraná' },
  c2: { x: 420, y: 350, region: 'São Paulo' },
  c3: { x: 410, y: 340, region: 'São Paulo' },
  c4: { x: 430, y: 360, region: 'São Paulo' },
  c5: { x: 405, y: 345, region: 'São Paulo' },
  c6: { x: 415, y: 335, region: 'São Paulo' },
  c7: { x: 350, y: 340, region: 'Interior SP' },
  c8: { x: 425, y: 355, region: 'São Paulo' },
  c9: { x: 410, y: 330, region: 'São Paulo' },
  c10: { x: 420, y: 365, region: 'São Paulo' },
  c11: { x: 380, y: 320, region: 'Minas Gerais' },
  c12: { x: 425, y: 340, region: 'São Paulo' },
  c13: { x: 400, y: 370, region: 'São Paulo' },
  c14: { x: 415, y: 345, region: 'São Paulo' },
  c15: { x: 300, y: 400, region: 'Santa Catarina' },
  c16: { x: 440, y: 310, region: 'Espírito Santo' },
  c17: { x: 410, y: 355, region: 'São Paulo' },
  c18: { x: 430, y: 375, region: 'São Paulo' },
  c19: { x: 390, y: 350, region: 'São Paulo' },
  c20: { x: 400, y: 330, region: 'São Paulo' },
  c21: { x: 370, y: 340, region: 'Interior SP' },
};

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'goals' | 'performance' | 't20' | 'efficiency' | 'geo'>('goals');
  const [selectedYear, setSelectedYear] = useState<string>('2026');
  const [saveFeedback, setSaveFeedback] = useState<boolean>(false);

  // Database Engine - Persistência Total SK-G (2026-2028)
  const [db, setDb] = useState<SKGDatabase>(() => {
    const initialRevenue: YearlyActualData = {};
    const initialOp: YearlyOperationalData = {};
    const initialT20: Record<string, Record<number, number>> = {};

    YEARS.forEach(yr => {
      initialRevenue[String(yr)] = {};
      initialOp[String(yr)] = {};
      MONTHS.forEach(m => { 
        initialRevenue[String(yr)][String(m)] = { syllas: 0, v1: 0, v2: 0, v3: 0 }; 
        initialOp[String(yr)][String(m)] = { zm: 0, terceiro: 0, correios: 0, mercadoria: 0 };
      });
    });

    HISTORICAL_TOP_CLIENTS.forEach(c => {
      initialT20[String(c.id)] = { 2026: 0, 2027: 0, 2028: 0 };
    });

    try {
      const saved = localStorage.getItem('SKG_BI_V25_FULL_DATABASE');
      if (saved) {
        const parsed = JSON.parse(saved);
        return {
          revenue: { ...initialRevenue, ...parsed.revenue },
          operational: { ...initialOp, ...parsed.operational },
          t20Projections: { ...initialT20, ...parsed.t20Projections }
        };
      }
    } catch (e) { console.warn("Database sync fail:", e); }
    return { revenue: initialRevenue, operational: initialOp, t20Projections: initialT20 };
  });

  const handleGlobalSave = () => {
    localStorage.setItem('SKG_BI_V25_FULL_DATABASE', JSON.stringify(db));
